const missions = msg.missions || [];
const messages = [];

for (const m of missions) {
    messages.push({
        url: 'https://external.dronesense.com/v1/drones/with-sensors',
        headers: { 'x-api-key': m.key },
        missionLabel: m.name
    });
}

return [messages];

// DroneSense API → CoT
//   Type selection per item:
//     - isDrone=true → a-f-A-M-H-Q (rotary UAV)
//     - isDrone=false with any sensor.rtsp_url → a-f-G-E-S (ground sensor w/ video)
//     - isDrone=false with no video → a-f-G-U-C (ground unit)
//   SPI (b-m-p-s-p-i) emitted only when spoiLat/spoiLng present (practically, drones).
//   Video <__video> element emitted for any item with an active sensor.
//
// Output 1: MediaMTX proxy register requests (one per active sensor)
// Output 2: CoT XML events (platform + optional SPI)

const items = msg.payload || [];
if (!Array.isArray(items)) return [null, null];

const missionLabel = msg.missionLabel || '';
const serverAddress = env.get('SERVER_ADDRESS') || 'localhost';
const staleSeconds = parseInt(env.get('DRONESENSE_STALE_SECONDS') || '10', 10);

function xmlEscape(s) {
    return String(s)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&apos;');
}

function pickCotType(item) {
    if (item.isDrone) return 'a-f-A-M-H-Q';
    const hasVideo = (item.sensors || []).some(s => s.rtsp_url);
    return hasVideo ? 'a-f-G-E-S' : 'a-f-G-U-C';
}

// Cache TLS fingerprints in flow context so we only TLS-connect once per host
const fpCache = flow.get('_dsFingerprintCache') || {};
const hostsToResolve = new Map();
for (const item of items) {
    if (!item.sensors) continue;
    for (const sensor of item.sensors) {
        if (!sensor.rtsp_url) continue;
        try {
            const u = new URL(sensor.rtsp_url);
            const hp = `${u.hostname}:${u.port}`;
            if (!fpCache[hp]) hostsToResolve.set(hp, { host: u.hostname, port: parseInt(u.port, 10) });
        } catch (e) {}
    }
}

function getFingerprint(host, port) {
    return new Promise((resolve) => {
        const sock = tls.connect({ host, port, rejectUnauthorized: false }, () => {
            const cert = sock.getPeerCertificate(true);
            const fp = crypto.createHash('sha256').update(cert.raw).digest('hex');
            sock.destroy();
            resolve(fp);
        });
        sock.on('error', () => resolve(''));
        sock.setTimeout(5000, () => { sock.destroy(); resolve(''); });
    });
}

async function run() {
    for (const [hp, info] of hostsToResolve) {
        const fp = await getFingerprint(info.host, info.port);
        if (fp) {
            fpCache[hp] = fp;
            node.log(`Cached TLS fingerprint for ${hp}: ${fp}`);
        }
    }
    flow.set('_dsFingerprintCache', fpCache);

    const proxyMsgs = [];
    const cotMsgs = [];
    const nowMs = Date.now();
    const time = new Date(nowMs).toISOString();
    const stale = new Date(nowMs + staleSeconds * 1000).toISOString();

    for (const item of items) {
        if (item.latitude == null || item.longitude == null) continue;

        const cotType = pickCotType(item);
        const platformUid = `ds-${item.id}`;
        const callsignBase = item.callSign || item.model || item.id;
        const displayCallsign = missionLabel ? `${missionLabel} // ${callsignBase}` : callsignBase;
        const model = item.model || 'Unknown';
        const hae = item.altitudeMsl != null ? item.altitudeMsl : 0;
        const course = item.heading != null ? item.heading : 0;
        // DroneSense uses -1 as invalid-speed sentinel
        const speed = (item.speed != null && item.speed >= 0) ? item.speed : 0;

        const hasSpi = item.spoiLat != null && item.spoiLng != null;
        const spiShort = hasSpi ? `${callsignBase}.SPI1` : '';

        // --- video element: empty when idle, short-form + ConnectionEntry when streaming ---
        const activeSensors = (item.sensors || []).filter(s => s.rtsp_url);
        let videoXml = '<__video/>';
        if (activeSensors.length > 0) {
            videoXml = '';
            for (const sensor of activeSensors) {
                let fingerprint = '';
                try {
                    const u = new URL(sensor.rtsp_url);
                    fingerprint = fpCache[`${u.hostname}:${u.port}`] || '';
                } catch (e) {}

                const proxyPath = `ds/${sensor.id}`;
                proxyMsgs.push({
                    url: `http://mediamtx:9997/v3/config/paths/add/${proxyPath}`,
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    payload: JSON.stringify({
                        source: sensor.rtsp_url,
                        sourceFingerprint: fingerprint,
                        sourceOnDemand: false
                    })
                });

                const proxyUrl = `rtsp://${serverAddress}:8554/${proxyPath}?tcp`;
                const feedUid = `ds-video-${sensor.id}`;
                const sensorName = sensor.name || callsignBase;
                const alias = missionLabel ? `${missionLabel} // ${sensorName}` : sensorName;

                videoXml +=
                    `<__video sensor="${xmlEscape(displayCallsign)}" spi="${xmlEscape(spiShort)}" url="${xmlEscape(proxyUrl)}">` +
                    `<ConnectionEntry networkTimeout="12000" uid="${xmlEscape(feedUid)}" ` +
                    `path="/${xmlEscape(proxyPath)}" protocol="rtsp" bufferTime="-1" ` +
                    `address="${xmlEscape(serverAddress)}" port="8554" roverPort="-1" rtspReliable="0" ` +
                    `alias="${xmlEscape(alias)}"/>` +
                    `</__video>`;
            }
        }

        const remarks = missionLabel ? `${model} — ${missionLabel}` : model;

        // --- platform event ---
        const platformCot =
            `<?xml version="1.0" encoding="UTF-8"?>` +
            `<event version="2.0" uid="${xmlEscape(platformUid)}" type="${cotType}" how="m-g" ` +
            `time="${time}" start="${time}" stale="${stale}">` +
            `<point lat="${item.latitude}" lon="${item.longitude}" hae="${hae}" ce="0.0" le="0.0"/>` +
            `<detail>` +
            `<contact callsign="${xmlEscape(displayCallsign)}"/>` +
            `<track course="${course}" slope="0.0" speed="${speed}"/>` +
            `<remarks>${xmlEscape(remarks)}</remarks>` +
            videoXml +
            `</detail>` +
            `</event>`;
        cotMsgs.push({ payload: platformCot });

        // --- SPI event — only when DroneSense gives us a ground intersection ---
        if (hasSpi) {
            const spiUid = `${callsignBase}.${platformUid}.SPI1`;

            const spiCot =
                `<?xml version="1.0" encoding="UTF-8"?>` +
                `<event version="2.0" uid="${xmlEscape(spiUid)}" type="b-m-p-s-p-i" how="m-g" ` +
                `time="${time}" start="${time}" stale="${stale}">` +
                `<point lat="${item.spoiLat}" lon="${item.spoiLng}" hae="0.0" ce="9999999.0" le="9999999.0"/>` +
                `<detail>` +
                `<contact callsign="${xmlEscape(spiShort)}"/>` +
                `<link uid="${xmlEscape(platformUid)}" type="${cotType}" relation="p-p"/>` +
                `<precisionlocation altsrc="GPS"/>` +
                `</detail>` +
                `</event>`;
            cotMsgs.push({ payload: spiCot });
        }
    }

    return [proxyMsgs, cotMsgs];
}

return run();
